INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-416.5, 1000001, "カリン", 1, 190801, 62, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", "2030/01/01 14:59:59", 0.0, 1, "2025/01/31 12:00:00", 3.414, 1, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-416.5, 1000002, "カリン", 1, 190801, 62, "ミッションをクリアして、\n報酬をゲットしましょう！", "2030/01/01 14:59:59", 0.0, 1, "2025/01/31 12:00:00", 3.099, 2, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-416.5, 1000003, "カリン", 1, 190801, 63, "受け取ることができる\n報酬があるようです\n確認してみてください", "2030/01/01 14:59:59", 0.0, 1, "2025/01/31 12:00:00", 2.801, 3, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-416.5, 1000004, "カリン", 2, 190801, 63, "報酬がもらえますよ！\nチェックしてみてください", "2030/01/01 14:59:59", 0.0, 1, "2025/01/31 12:00:00", 0.0, 4, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-363.0, 1000005, "カリン", 2, 190801, 64, "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", "2030/01/01 14:59:59", 0.0, 1, "2025/01/31 12:00:00", 2.12, 5, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-363.0, 1000006, "カリン", 1, 190801, 64, "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", "2030/01/01 14:59:59", 0.0, 1, "2025/01/31 12:00:00", 1.68, 6, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-363.0, 1000007, "カリン", 2, 190801, 64, "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", "2030/01/01 14:59:59", 0.0, 1, "2025/01/31 12:00:00", 2.33, 7, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1020101, "ラビリスタ", 3, 133701, 61, "今度の敵は、アタシにとっても\n放ってはおけない存在だ\n少年、アタシも全力で行くからさ\n一緒に守ろう、この世界を", "2030/01/01 14:59:59", -6.0, 10201, "2025/01/31 12:00:00", 5.18, 101, 7);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1020102, "クリスティーナ", 1, 133901, 61, "退屈の吹き飛ぶような\n戦いの気配がするなぁ坊や\nさっさとワタシをそこへ連れてゆけ\n世界も守ってやるさ、ついでにな", "2030/01/01 14:59:59", -2.0, 10201, "2025/01/31 12:00:00", 8.77, 201, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1020103, "ネネカ", 6, 133801, 61, "おや、私の力が必要……と？\nグレゴールが手伝うそうですよ\n私は戦わないのか、という顔ですね\n……考えておきます", "2030/01/01 14:59:59", 0.0, 10201, "2025/01/31 12:00:00", 15.5, 301, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1020201, "ランファ", 2, 134301, 61, "わたしだけの歌…\n一緒に、探してくれる…？\nあなたがいれば…\nもっとがんばれるから…", "2030/01/01 14:59:59", 0.0, 10202, "2025/02/28 12:00:00", 9.061, 101, 5);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1020202, "チカ", 1, 134401, 61, "同じ唱喚士として、仲間として\n私にできることをします\n…これも、あなたが\n背中を押してくれたおかげですよ", "2030/01/01 14:59:59", 0.0, 10202, "2025/02/28 12:00:00", 7.699, 201, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1020301, "アオイ", 1, 134601, 61, "世界の平和が私とクローチェさんに\nかかってるんですよね？\nぼっちには過大すぎる期待ですけど\nふ、二人でなら背負ってみせます！", "2030/01/01 14:59:59", 0.0, 10203, "2025/03/31 12:00:00", 8.595, 101, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1020302, "クローチェ", 1, 134501, 61, "新しく手に入れたこの翼で…\nナイトさんがどこにいたって\nわたし、駆けつけちゃいますよっ！\nクローチェ・エアリアル発進ですっ", "2030/01/01 14:59:59", 0.0, 10203, "2025/03/31 12:00:00", 7.758, 201, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1020401, "ルイズマリー", 2, 132302, 61, "今日はダーリンとの初デート♪\n二人でショッピングして、その後は\n…って私、指名手配されてる！？\nちょ、た…助けてダーリン～！！", "2030/01/01 14:59:59", 0.0, 10204, "2025/04/30 12:00:00", 7.0, 101, 6);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1020402, "イロハ", 1, 132402, 61, "ルイちゃんのおばあちゃん優しくて\nいつもにこにこで、イロハ大好き♪\nでも一番好きなのは、角がすっごく\n大きくてかっこいいとこなんだ～♪", "2030/01/01 14:59:59", 0.0, 10204, "2025/04/30 12:00:00", 7.904, 201, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1020403, "ソノ", 4, 132502, 61, "ノゾミちゃんのおかげで売上が安定\nしてきたのに、臨時休業、痛すぎる\n…ま、ルイちゃんのために\n一肌脱ぐか。行くよイロハ～", "2030/01/01 14:59:59", 0.0, 10204, "2025/04/30 12:00:00", 8.487, 301, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1020502, "カノン", 1, 134901, 61, "ヲ～ッホッホ♪\nあたくし様と同じお空気を吸える\nお幸運を噛みしめなさいですわ～♪\nヲ～ッホッホッホ～♪", "2030/01/01 14:59:59", 0.0, 10205, "2025/05/31 12:00:00", 8.763, 101, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1020503, "ツムギ", 1, 134801, 61, "いきますよ騎士さん！\nカノンさんと力を合わせて…力を…\n…本当にあの人なんなんです？\nこれまでになく不安なんですけど！", "2030/01/01 14:59:59", 0.0, 10205, "2025/05/31 12:00:00", 6.417, 201, 3);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1020601, "エリス", 3, 135001, 61, "『願いが叶う海岸』か…怪しい\nだというのに、阿賀斗紫布菜たちは\n呑気に戯れている…見ていられない\n騎士クンは、わたしが守ってみせる", "2030/01/01 14:59:59", 0.0, 10206, "2025/06/30 12:00:00", 10.335, 101, 7);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1020602, "シェフィ", 2, 135101, 61, "せっかくの夏休みなんだし\nたまにはビーチでゆっくりしましょ\n…え、もしかしてこの夏もあんまり\n休めなかったりする感じなの？", "2030/01/01 14:59:59", 0.0, 10206, "2025/06/30 12:00:00", 6.281, 201, 4);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1020603, "プレシア", 1, 135201, 61, "いっぱい。たべて\nおおきく。なると\nせーぎ。まもれる。はず\nお兄。いっしょに。スイカ。たべよ", "2030/01/01 14:59:59", 0.0, 10206, "2025/06/30 12:00:00", 12.244, 301, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1020701, "クリア", 2, 135301, 61, "ひと夏の冒険のはじまりです！\nアネモネさんも楽しんでくれたら\n…できれば、もう少し\n仲良くなれたらうれしいな…", "2030/01/01 14:59:59", 0.0, 10207, "2025/07/31 12:00:00", 6.339, 101, 8);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1020702, "アネモネ", 7, 135401, 61, "─幻の花…\n本当にあるのか謎─ですけど\n探すくらいは、\n付き合ってもいいです", "2030/01/01 14:59:59", 0.0, 10207, "2025/07/31 12:00:00", 8.184, 201, 9);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1020801, "アイラ", 9, 129101, 61, "あははっ！　笑う門には福来る！\n笑ってればきっと、複製世界にも\n未来はやってくるって信じてる！\nそうだよね、シナツちゃん！", "2030/01/01 14:59:59", 0.0, 10208, "2025/08/31 12:00:00", 3.906, 101, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1020802, "シナツ", 1, 129201, 61, "繰り返されるリセットの先の未来\n何度願っても手に入らなかった未来\n…でも、私は諦めない。絶対にだ\nキミも同じだろ…アイラ？", "2030/01/01 14:59:59", 0.0, 10208, "2025/08/31 12:00:00", 14.465, 201, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1020803, "ヒヨリ", 4, 100101, 61, "アイラの世界のみんなも、\n一生懸命生きてるんだ…！\n…なのに、世界の危機だなんて！\nあたし、絶対、絶対力になるよ！", "2030/01/01 14:59:59", 0.0, 10208, "2025/08/31 12:00:00", 8.662, 301, 3);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1020804, "レイ", 1, 100301, 61, "シナツ…もう一人の私\n彼女が大切にしている世界を\n絶対に終わらせはしない…！\n彼女と笑い合える未来のために！", "2030/01/01 14:59:59", 0.0, 10208, "2025/08/31 12:00:00", 10.915, 401, 3);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1020901, "ユキノ", 1, 135802, 61, "あ、ど、ども…\nあ、あんま見ねぇでくれっと\nその、恥ずかしくて…\n体が熱くなって、溶けちまう…", "2030/01/01 14:59:59", 0.0, 10209, "2025/09/30 12:00:00", 6.042, 101, 7);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1020902, "サツキ", 4, 135903, 61, "なんで俺が幽霊に…意味不明だ\nこれじゃ死んでも死にきれねェ\n悪ィがこれも何かの縁だ、\nよろしく頼むぜ騎士公", "2030/01/01 14:59:59", 0.0, 10209, "2025/09/30 12:00:00", 9.402, 201, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1020903, "ルルィ", 8, 136902, 61, "う、うじゅる…\nサツキ姉しゃまを助けるためにも\nまずは、腹ごしらえでしゅね…！\nタコ焼き、召し上がってくだしゃい", "2030/01/01 14:59:59", 0.0, 10209, "2025/09/30 12:00:00", 8.16, 301, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1021001, "カスミ", 3, 137401, 61, "ひさしぶりのジオ・ゲヘナ\n歓迎パーティーで起きた殺人事件！\nランドソルの名探偵の名にかけて\n解き明かしてみせようじゃないか！", "2030/01/01 14:59:59", 0.0, 10210, "2025/10/31 12:00:00", 5.0, 101, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1021002, "アラクネ", 4, 136001, 61, "…わたしはどこの誰なのでしょう\nどこから来てどこへ行くのでしょう\nこの事件の真相が分かれば、\n何かが掴めるような気がいたします", "2030/01/01 14:59:59", 0.0, 10210, "2025/10/31 12:00:00", 8.12, 201, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1021003, "ナーナ", 4, 136202, 61, "ナーナ、すいりとかろんぱとか、\nむずかしくてわかんないけど…\nお友だちとドーナツのためならっ\nせーいっぱいがんばるよっ！", "2030/01/01 14:59:59", 0.0, 10210, "2025/10/31 12:00:00", 6.386, 301, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1021101, "ユイ", 3, 136402, 61, "騎士クンに想いを伝えたい…だから\nミソラちゃん、わたしがんばるね！\n…あれ？　わたし、なんでこんなに\n必死になってるんだろう…？", "2030/01/01 14:59:59", 0.0, 10211, "2025/11/30 12:00:00", 7.438, 101, 4);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1021102, "ミソラ", 1, 136302, 61, "騎士さんとのデートはわたしに\nお任せです★　なのでユイさんは\n安心して計画に専念して…たくさん\nドキドキしちゃってくださいね", "2030/01/01 14:59:59", 0.0, 10211, "2025/11/30 12:00:00", 8.35, 201, 5);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1021201, "シズル", 1, 136501, 61, "新しい年がやってくるね！\nお正月の料理も飾りつけも、\nお姉ちゃんにお任せだよ♪\nみんなで楽しく新年を迎えよう！", "2030/01/01 14:59:59", 0.0, 10212, "2025/12/31 12:00:00", 5.0, 101, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1021202, "リノ", 1, 137902, 61, "おうちの掃除もトラブルも、 \n世界を揺るがす大ピンチも！\n今年のことは今年のうちに \nサッサと片付けちゃいますっ！", "2030/01/01 14:59:59", 0.0, 10212, "2025/12/31 12:00:00", 5.25, 201, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1021203, "ラビリスタ", 1, 106801, 61, "年の瀬はギルドマスターも\nつい駆け回っちゃう忙しい時期だ！\n一年いろいろあったけど\nお互いイイ年を迎えよう、少年！", "2030/01/01 14:59:59", 0.0, 10212, "2025/12/31 12:00:00", 7.5, 301, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1021301, "ライラエル", 1, 126501, 61, "漂う異国の料理の香り…それだけで\n世界中を旅した気分に浸れますね\nふふ、ほらクローチェ\nあまりはしゃぎすぎないように…♪", "2030/01/01 14:59:59", 0.0, 10213, "2026/01/31 12:00:00", 8.204, 101, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1021302, "ネフィ＝ネラ", 1, 129701, 61, "異界の姫君と煮炊きにて競い合う…\n感奮興起、いとをかし\n華やかなる祭典と相成るよう、一肌\n脱がせていただきとう存じまする", "2030/01/01 14:59:59", 0.0, 10213, "2026/01/31 12:00:00", 7.176, 201, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1021303, "ヴァイオレット", 1, 133101, 61, "『ビストロプリンセス』のために\n料理の特訓を重ねてまいりました\nこの料理で騎士様の…い、いえ\n皆様の心とお腹を満たしますわ！", "2030/01/01 14:59:59", 0.0, 10213, "2026/01/31 12:00:00", 8.602, 301, 5);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1021304, "ライラエル", 1, 138101, 61, "多様な味わいが織りなすハーモニー\nそれこそが我が国の矜持です\nもしもそれを乱すようであれば\nわたしも優しくはありませんよ？", "2030/01/01 14:59:59", 0.0, 10213, "2026/02/06 12:00:00", 10.14, 102, 3);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1021305, "ネフィ＝ネラ", 1, 138201, 61, "煉獄の穢土にてひと際輝く民草の心\n此れを守護りまするがわっちの責務\n如何な困難待ち受けようと\n不退転の矜持に揺らぎはありんせん", "2030/01/01 14:59:59", 0.0, 10213, "2026/02/06 12:00:00", 10.152, 202, 7);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1021306, "ヴァイオレット", 4, 138001, 61, "裏世界の皆様は危機を脱し、\n残るはランドソルの皆様のみ…\n彼らを救い出すために、どうか…\nお立ち下さいペコリーヌ姫…！", "2030/01/01 14:59:59", 0.0, 10213, "2026/02/06 12:00:00", 9.688, 302, 3);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1021307, "ペコリーヌ", 2, 138301, 61, "みなさん、お待たせしちゃいました\nペコリーヌ、完全復活です☆\nみなさんの食卓を守るため\nもう二度と、わたしはめげません！", "2030/01/01 14:59:59", 0.0, 10213, "2026/02/12 12:00:00", 5.928, 401, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1021401, "ワカナ", 4, 138702, 61, "成行きで参加することになっちゃっ\nた尻相撲大会。ううっ、恥ずかしい\nけどやるしかないよね。…騎士さん\nいっぱい応援してくださいね？", "2030/01/01 14:59:59", 0.0, 10214, "2026/02/28 12:00:00", 9.19, 101, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1021402, "シオリ", 1, 138802, 61, "「お姉ちゃんを守れる自分になる」\nあの日の約束、今こそ果たしてみせ\nます。例えお姉ちゃんに背くことに\nなっても。例えそれが尻相撲でも！", "2030/01/01 14:59:59", 0.0, 10214, "2026/02/28 12:00:00", 8.724, 201, 3);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1021501, "グレイス", 4, 138902, 61, "私がへんたいふしんしゃさんって…\nただ生きているだけなのに、ひどい\n…まぁ死んでるんですけど…とか\n言ってる暇もない感じですか？", "2030/01/01 14:59:59", 0.0, 10215, "2026/03/31 12:00:00", 7.758, 101, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1021502, "キョウカ", 6, 139002, 61, "あの、助けてください！\n私がへんたいふしんしゃさんに\nなっちゃったみたいなんです…！\nどういう意味かは私もわかりません", "2030/01/01 14:59:59", 0.0, 10215, "2026/03/31 12:00:00", 6.375, 201, 4);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1021503, "ルルィ", 6, 136902, 61, "ましゃか、グレイス姉しゃまたちが\nへんたいふしんしゃさんだなんて…\n騎士しゃん。あたちたちも協力ちて\n二人の破滅エンドを回避ちましょう", "2030/01/01 14:59:59", 0.0, 10215, "2026/03/31 12:00:00", 6.173, 301, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1021601, "ミホ", 6, 139202, 61, "違う世界に来ちゃうし、\n驚きの連続だけど…\nわたしも精いっぱい頑張ります！\nアストルムのみんなと一緒に！", "2030/01/01 14:59:59", 0.0, 10216, "2026/04/30 12:00:00", 4.202, 101, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1021602, "マホ", 6, 139302, 61, "想定外の事象が発生したな…だが\nいかなる苦境も切り抜けてみせる\nいつもの自分とは違う姿になっても\nわたしはわたし、西住流だ", "2030/01/01 14:59:59", 0.0, 10216, "2026/04/30 12:00:00", 2.842, 201, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-285.0, 1021603, "エリカ", 4, 139402, 61, "何でこんなことになっているのか\n全然わからないけど、迷ってる暇は\nないわ。黒森峰の次期隊長として、\n前進あるのみ！　これも戦車道よ！", "2030/01/01 14:59:59", 0.0, 10216, "2026/04/30 12:00:00", 4.598, 301, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-416.5, 2000001, "カリン", 1, 190801, 62, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", "2030/01/01 14:59:59", 0.0, 2, "2026/04/10 12:00:00", 3.414, 1, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-416.5, 2000002, "カリン", 1, 190801, 62, "ミッションをクリアして、\n報酬をゲットしましょう！", "2030/01/01 14:59:59", 0.0, 2, "2026/04/10 12:00:00", 3.099, 2, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-416.5, 2000003, "カリン", 1, 190801, 63, "受け取ることができる\n報酬があるようです\n確認してみてください", "2030/01/01 14:59:59", 0.0, 2, "2026/04/10 12:00:00", 2.801, 3, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-416.5, 2000004, "カリン", 2, 190801, 63, "報酬がもらえますよ！\nチェックしてみてください", "2030/01/01 14:59:59", 0.0, 2, "2026/04/10 12:00:00", 0.0, 4, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-363.0, 2000005, "カリン", 2, 190801, 64, "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", "2030/01/01 14:59:59", 0.0, 2, "2026/04/10 12:00:00", 2.12, 5, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-363.0, 2000006, "カリン", 1, 190801, 64, "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", "2030/01/01 14:59:59", 0.0, 2, "2026/04/10 12:00:00", 1.68, 6, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (-363.0, 2000007, "カリン", 2, 190801, 64, "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", "2030/01/01 14:59:59", 0.0, 2, "2026/04/10 12:00:00", 2.33, 7, 1);
